// Login.jsx - With language support
import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LanguageContext } from '../App';
import { LogoFull } from '../components/Logo';
import s from './Auth.module.css';

export default function Login() {
  const nav = useNavigate();
  const { login } = useAuth();
  const { t } = useContext(LanguageContext);
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async e => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await login(form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || (t.loginError || 'Email ou mot de passe incorrect.'));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <button onClick={() => nav('/')} className={s.back}>← {t.home || 'Accueil'}</button>
      <div className={s.card}>
        <div className={s.cardLogo}><LogoFull size={32} /></div>
        <h1 className={s.title}>{t.welcomeBack || 'Bon retour !'}</h1>
        <p className={s.sub}>{t.signInToContinue || 'Connectez-vous pour continuer'}</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}>
            <label className={s.label}>{t.email || 'Email'}</label>
            <input className={s.input} type="email" placeholder="vous@exemple.com" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>{t.password || 'Mot de passe'}</label>
            <input className={s.input} type="password" placeholder="••••••••" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required />
          </div>
          <button className={s.submit} disabled={loading}>{loading ? 'Connexion...' : (t.signIn || 'Se connecter →')}</button>
        </form>
        <p className={s.switch}>{t.noAccount || 'Pas encore de compte ?'} <Link to="/register" className={s.link}>{t.createAccount || 'Créer un compte'}</Link></p>
      </div>
    </div>
  );
}
